#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int **A = (int**)malloc(N*sizeof(int*));
        for(int i=0;i<N;i++){
            A[i]=(int*)malloc(N*sizeof(int));
            for(int j=0;j<N;j++) scanf("%d", &A[i][j]);
        }
        int **B = (int**)malloc((N+1)*sizeof(int*));
        for(int i=0;i<=N;i++){
            B[i]=(int*)calloc(N+1, sizeof(int));
        }
        for(int i=0;i<N;i++){
            for(int j=0;j<N;j++){
                B[i+1][j+1] = A[i][j] - B[i][j] - B[i+1][j] - B[i][j+1];
            }
        }
        for(int i=0;i<=N;i++){
            for(int j=0;j<=N;j++){
                if(j) printf(" ");
                printf("%d", B[i][j]);
            }
            printf("\n");
        }
        for(int i=0;i<N;i++) free(A[i]);
        free(A);
        for(int i=0;i<=N;i++) free(B[i]);
        free(B);
    }
    return 0;
}

