import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        A = [[int(next(it)) for _ in range(N)] for _ in range(N)]
        B = [[0]*(N+1) for _ in range(N+1)]
        for i in range(N):
            for j in range(N):
                B[i+1][j+1] = A[i][j] - B[i][j] - B[i+1][j] - B[i][j+1]
        for i in range(N+1):
            out_lines.append(' '.join(str(x) for x in B[i]))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

